            "op": "get",
            "field": "host_type"
          }
        ]
      },
      "expected_output": "url=valid\nhost_type=ipv6\n"
    }
  ]
}

Here are the public test cases for feature7_set_scheme:
{
  "description": "Change the scheme of a parsed URL and observe the result. Switching between compatible schemes succeeds and re-serializes the URL under the new scheme; switching a scheme is rejected (reported as failure, leaving the URL unchanged) when the transition is not allowed for the current URL shape. When a scheme change brings the host's default port into effect, that port is dropped from the serialization.",
  "cases": [
    {
      "input": {
        "action": "parse_url",
        "url": "https://www.google.com",
        "steps": [
          {
            "op": "set",
            "field": "protocol",
            "value": "wss"
          },
          {
            "op": "get",
            "field": "protocol"
          },
          {
            "op": "get",
            "field": "href"
          }
        ]
      },
      "expected_output": "url=valid\nset_protocol=true\nprotocol=wss:\nhref=wss://www.google.com/\n"
    },
    {
      "input": {
        "action": "parse_url",
        "url": "http://www.google.com:443",
        "steps": [
          {
            "op": "set",
            "field": "protocol",
            "value": "https"
          },
          {
            "op": "get",
            "field": "port"
          },
          {
            "op": "get",
            "field": "host"
          }
        ]
      },
      "expected_output": "url=valid\nset_protocol=true\nport=\nhost=www.google.com\n"
    }
  ]
}

Here are the public test cases for feature8_set_host:
{
  "description": "Set the host (or the bare hostname) of a parsed URL. For a URL that has an authority, a syntactically valid replacement succeeds and is reflected when reading the host back; an invalid host value is rejected and leaves the URL unchanged. For a URL whose scheme cannot carry a host, the operation is rejected.",
  "cases": [
    {
      "input": {
        "action": "parse_url",
        "url": "https://www.google.com",
        "steps": [
          {
            "op": "set",
            "field": "host",
            "value": "github.com"
          },
          {
            "op": "get",
            "field": "host"
          }
        ]
      },
      "expected_output": "url=valid\nset_host=true\nhost=github.com\n"
    },
    {
      "input": {
        "action": "parse_url",
        "url": "mailto:a@b.com",
        "steps": [
          {
            "op": "set",
            "field": "host",
            "value": "something"
          }
        ]
      },
      "expected_output": "url=valid\nset_host=false\n"
    }
  ]
}

